import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat updated = original.withIgnoreSurroundingSpaces();

        assertNotNull(updated, "Updated CSVFormat should not be null");
        assertTrue(updated.getIgnoreSurroundingSpaces(), "IgnoreSurroundingSpaces should be true");
        // Original instance should remain unchanged
        assertFalse(original.getIgnoreSurroundingSpaces(), "Original CSVFormat should have ignoreSurroundingSpaces false");
    }
}
